var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니까...... 여기서 혼자 20년을 버텨 왔다고?","JPN":"だから……ここで一人で20年も耐えてきたの？","ENG":"So you're saying... you survived alone here for 20 years?","TWN":"所以說……妳一個人在這裡待了20年？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"20년?","JPN":"20年……？","ENG":"20 years?","TWN":"20年？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"시간이...... 벌써 그렇게 흘렀나?","JPN":"もう……そんなに時が経ったのか？","ENG":"Has it been that long already?","TWN":"已經過了……這麼長的時間了？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"실감이 나지 않아. 날짜를 세는 건 오래 전에 포기했거든.","JPN":"実感が湧かないな。\\n日にちを数えるのも、とうの昔にやめていたものでね。","ENG":"It hardly feels like it's been that long. I gave up on keeping count of the days a long time ago.","TWN":"真沒有實感，我很早就放棄計算日期了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 굉장하군. 쉬운 일은 아니었을 텐데.","JPN":"それにしてもすごいな。生半可なことではなかっただろう。","ENG":"Still, it's very impressive. It couldn't have been easy.","TWN":"但這仍舊很厲害，真是不簡單。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어째서 도망치지 않았나?","JPN":"なぜ逃げ出さなかったんだ？","ENG":"Why didn't you run?","TWN":"妳為什麼沒逃跑？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그게 더 현명한 판단이었을지도 모르지.","JPN":"その方が賢明だったかもしれないな。","ENG":"Perhaps that would have been the prudent thing to do.","TWN":"或許那才是明智的判斷。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 도플갱어들이 대원들을 노리고 있는데 나 혼자 떠날 수는 없었다.","JPN":"しかし、隊員たちがドッペルゲンガーに狙われているときに\\n私一人だけで離脱することはできなかった。","ENG":"But I could not leave my troops behind, not when the Doppelgangers were after them.","TWN":"但二重身們對我的隊員虎視眈眈，我不能丟下他們不管。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"다행히 이 근처엔 쓸 만한 물건이 많았어.","JPN":"幸い、この辺りには使えそうな物が多かった。","ENG":"Fortunately, there was plenty of useful stuff around here.","TWN":"幸虧附近有很多有用的東西。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"버려진 함선에 무기와 보급품이 실려 있었으니까.","JPN":"打ち捨てられた艦船には、武器や補給品も積んであったからな。","ENG":"The abandoned ships were loaded with weaponry and supplies.","TWN":"廢棄的艦船上裝載著武器和補給品。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"특히 기갑 병기들이 유용했다. 관제사를 지망하던 시절 정비 기술을 배웠거든.","JPN":"機甲兵器は特に役に立ってくれた。管制官を\\n志していた頃に整備技術を習っておいたおかげでな。","ENG":"The armored vehicles were particularly useful. When I was a prospective air traffic controller, I also learned how to perform maintenance.","TWN":"尤其是機械兵器非常有用。我以前志願成為管制員的時候，曾經學過整備技術。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러고 보니......","JPN":"そういえば……","ENG":"Oh... Come to think of it...","TWN":"話說回來……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오는 도중 공격해 왔던 기갑 병기들의 인공지능에 누군가가 조작한 흔적이 있었지.","JPN":"途中で攻撃してきた機甲兵器類の人工知能に、\\n何者かによる操作の痕跡があったな。","ENG":"I did notice someone tampered with the A.I. of the armored vehicles that attacked us on the way here.","TWN":"在路上攻擊我們的機械兵器，上面的人工智慧留有被人操作的痕跡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이제 보니 자네가 한 일이었군.","JPN":"あれは君の手によるものだったか。","ENG":"So that was your doing.","TWN":"原來那是妳做的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"정보 오염이 심각하게 진행된 기체들을 제외하면 말이지.","JPN":"情報汚染が深刻に進んだ機体を除けばそのとおりだ。","ENG":"Except the ones that had their data corrupted beyond repair.","TWN":"除了資訊污染極其嚴重的機體以外。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이 곳에서 달리 아군을 구할 수는 없었으니까.","JPN":"ここでは他に味方を募ることもできなかったからな。","ENG":"There was no other way to secure allies around here.","TWN":"因為我在這裡沒辦法找到其他友軍。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 너희들까지 공격에 휘말렸다니 마무리가 조금 서툴렀나 보군. 미안하다.","JPN":"だが、お前たちまで攻撃に巻き込まれていたとは……\\n仕上げが少々粗かったのかもしれん。すまない。","ENG":"But I suppose the calibrations could use a little more work since they attacked you as well. Sorry about that.","TWN":"但沒想到連你們也被它們攻擊了，看來是我搞砸了，抱歉。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};